const docs = Array.isArray(msg.payload) ? msg.payload : [];

// Build table-ready asset list
const assets = docs.map(d => ({
    id: d.uniqueId,
    assets: d.title || '-',
    type: d.type || 'Dataset',
    name: d.catalogue || '-',
    domain: d.domain || d.catalogue || '-',
    updated: (d.harvestedAt || d.createdAt || '-').replace('T', ' ').slice(0, 19),
    integrationStatus: d.status || 'Active',
    harvestRunId: d.harvestRunId || '',
    sourceAssetId: d.sourceAssetId || '',
    strategy: d.strategy || '',
    catalogueId: d.catalogueId || '',
    harvestScope: d.harvestScope || {},
    uniqueId: d.uniqueId
}));

assets.sort((a, b) => (b.updated || '').localeCompare(a.updated || ''));

// Compute stats
const runIds = new Set();
for (const d of docs) { if (d.harvestRunId) runIds.add(d.harvestRunId); }

msg.response = {
    action: 'getLocalCatalogue',
    status: 'success',
    assets: assets,
    totalAssets: assets.length,
    totalRuns: runIds.size
};
delete msg.payload;
return msg;

const uid = msg.data?.uniqueId || msg.data?.assetId || '';
msg._assetId = uid;
msg.operation = 'find';
msg.collection = 'lc_assets';
msg.payload = [{ uniqueId: uid }];
return msg;

const docs = Array.isArray(msg.payload) ? msg.payload : [];
const asset = docs[0] || null;
msg.response = {
    action: 'getLocalAssetDetail',
    status: 'success',
    asset: asset
};
delete msg.payload;
delete msg._assetId;
return msg;

const uid = msg.data?.uniqueId;
if (!uid) {
    msg.response = {
        action: 'deleteLocalAsset',
        status: 'error',
        message: 'Missing uniqueId'
    };
    delete msg.payload;
    return [null, msg];
}
msg.operation = 'deleteOne';
msg.collection = 'lc_assets';
msg.payload = { uniqueId: uid };
return [msg, null];

msg.response = {
    action: 'deleteLocalAsset',
    status: 'success'
};
delete msg.payload;
return msg;

const uid = msg.data?.uniqueId;
const patch = msg.data?.patch || {};
if (!uid) {
    msg.response = {
        action: 'updateLocalAsset',
        status: 'error',
        message: 'Missing uniqueId'
    };
    delete msg.payload;
    return [null, msg];
}
patch.updatedAt = new Date().toISOString();
msg.operation = 'updateOne';
msg.collection = 'lc_assets';
msg.payload = [
    { uniqueId: uid },
    { $set: patch }
];
return [msg, null];

msg.response = {
    action: 'updateLocalAsset',
    status: 'success'
};
delete msg.payload;
return msg;

const docs = Array.isArray(msg.payload) ? msg.payload : [];
const provenance = [];
for (const d of docs) {
    if (Array.isArray(d.provenance)) {
        for (const p of d.provenance) provenance.push(p);
    }
}
msg.response = {
    action: 'getLocalProvenance',
    status: 'success',
    provenance: provenance,
    total: provenance.length
};
delete msg.payload;
return msg;

const docs = Array.isArray(msg.payload) ? msg.payload : [];

const runIds = new Set();
const catalogueIds = new Set();
const statusCounts = { Active: 0, Warning: 0, Error: 0, Archived: 0 };

for (const d of docs) {
    if (d.harvestRunId) runIds.add(d.harvestRunId);
    if (d.catalogueId || d.catalogue) catalogueIds.add(d.catalogueId || d.catalogue);
    const s = d.status || 'Active';
    if (statusCounts[s] !== undefined) statusCounts[s]++;
    else statusCounts.Active++;
}

msg.response = {
    action: 'getLocalStats',
    status: 'success',
    totalAssets: docs.length,
    totalRuns: runIds.size,
    linkedCatalogues: catalogueIds.size,
    totalProvenance: docs.length,
    statusCounts: statusCounts,
    warningCount: statusCounts.Warning,
    errorCount: statusCounts.Error
};
delete msg.payload;
return msg;
